
/* =========================
   Learnly — front-end prototype
   All data is local; no backend.
   ========================= */

const APP = (() => {
  // sample catalog with working images
  const CATALOG = [
    { id:'c-react', title:'React Essentials', category:'Web', price:0, rating:4.8, duration:'6h', lessons: [
        {id:'r1', title:'Intro & JSX', duration:'12m'},
        {id:'r2', title:'Components & Props', duration:'25m'},
        {id:'r3', title:'State & Lifecycle', duration:'28m'},
        {id:'r4', title:'Hooks Basics', duration:'30m'},
        {id:'r5', title:'Build: Todo App', duration:'40m'}
      ],
      instructor:'Alex Kim',
      img:'data:image/png;base64,',
      desc:'Start building reactive web apps with components, hooks and practical examples.'
    },
    { id:'c-css', title:'Modern CSS & Layouts', category:'Web', price:499, rating:4.6, duration:'4.5h',
      lessons:[{id:'css1',title:'Flexbox Deep Dive',duration:'22m'},{id:'css2',title:'Grid Layout',duration:'30m'},{id:'css3',title:'Responsive Patterns',duration:'26m'}],
      instructor:'Priya Sharma',
      img:'data:image/jpeg;base64,',
    },
    { id:'c-ml', title:'Intro to Machine Learning', category:'AI', price:1299, rating:4.7, duration:'10h',
      lessons:[{id:'ml1',title:'Statistics Refresher',duration:'40m'},{id:'ml2',title:'Regression',duration:'50m'},{id:'ml3',title:'Classification',duration:'55m'}],
      instructor:'Dr. Lina Gomez',
      img:'data:image/jpeg;base64,',
      desc:'A practical introduction to ML concepts, models and evaluation.'
    },
    { id:'c-ux', title:'Design Thinking & UX', category:'Design', price:699, rating:4.5, duration:'5h',
      lessons:[{id:'ux1',title:'Research Methods',duration:'20m'},{id:'ux2',title:'Prototyping',duration:'36m'}],
      instructor:'Sam Lee',
      img:'data:image/png;base64,',
      desc:'Learn to design with empathy, sketches, and rapid prototypes.'
    },
    { id:'c-data', title:'Data Visualization with D3', category:'Data', price:999, rating:4.4, duration:'7h',
      lessons:[{id:'d1',title:'SVG Basics',duration:'18m'},{id:'d2',title:'Scales & Axes',duration:'24m'},{id:'d3',title:'Interactive Charts',duration:'32m'}],
      instructor:'Marco Ruiz',
      img:'data:image/jpeg;base64,',
      desc:'From basics to interactive visualizations with D3.js.'
    }
  ];

 
  const STORAGE_KEY = 'learnly_state_v1';
  let STATE = loadState();

  function loadState(){
    try{
      const raw = localStorage.getItem(STORAGE_KEY);
      if(!raw) return { enrolled: {}, progress: {} };
      return JSON.parse(raw);
    }catch(e){ return { enrolled: {}, progress: {} }; }
  }
  function saveState(){ localStorage.setItem(STORAGE_KEY, JSON.stringify(STATE)); }

  
  const $ = sel => document.querySelector(sel);
  const $$ = sel => Array.from(document.querySelectorAll(sel));
  const coursesGrid = $('#coursesGrid');
  const chipsWrap = $('#categoryChips');
  const qInput = $('#q');
  const sortSel = $('#sort');
  const resultCount = $('#resultCount');
  const modalBack = $('#modalBack');
  const modal = $('#modal');
  const myCoursesWrap = $('#myCourses');
  const overallBar = $('#overallBar');
  const overallPct = $('#overallPct');
  const playerArea = $('#playerArea');
  const lessonsList = $('#lessonsList');

  
  const categories = ['All', ...Array.from(new Set(CATALOG.map(c=>c.category)))];
  categories.forEach(cat => {
    const b = document.createElement('button');
    b.className = 'chip' + (cat==='All'?' active':'');
    b.textContent = cat;
    b.dataset.cat = cat;
    chipsWrap.appendChild(b);
    b.addEventListener('click', ()=> {
      chipsWrap.querySelectorAll('.chip').forEach(x=>x.classList.remove('active'));
      b.classList.add('active');
      renderGrid();
    });
  });

  
  qInput.addEventListener('input', ()=> renderGrid());
  sortSel.addEventListener('change', ()=> renderGrid());


  $('#themeToggle').addEventListener('click', ()=>{
    document.documentElement.style.colorScheme = document.documentElement.style.colorScheme === 'light' ? 'dark' : 'light';
    
    if(document.body.style.backgroundColor){
      document.body.style.backgroundColor = '';
    } else {
      document.body.style.backgroundColor = '#fff';
      document.body.style.color = '#02121a';
    }
  });


  $('#featuredCourse').addEventListener('click', ()=> openCourseModal('c-react'));

 
  $('#browseBtn').addEventListener('click', ()=> window.scrollTo({top: document.querySelector('.filters').offsetTop, behavior:'smooth'}));

 
  $('#exportData').addEventListener('click', ()=> {
    const blob = new Blob([JSON.stringify(STATE, null, 2)], { type: 'application/json' });
    const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = 'learnly_state.json'; a.click();
  });

  
  $('#startQuiz').addEventListener('click', ()=> openQuizModal());

  
  $('#openProfile').addEventListener('click', ()=> openProfileModal());

 
  $('#myDashboard').addEventListener('click', ()=> scrollToDashboard());

  
  const formatPrice = p => p === 0 ? 'Free' : `₹${p.toLocaleString('en-IN')}`;

  
  function renderGrid(){
    const q = qInput.value.trim().toLowerCase();
    const cat = chipsWrap.querySelector('.chip.active')?.dataset.cat || 'All';
    const sort = sortSel.value;
    let items = CATALOG.filter(c => (cat==='All' || c.category===cat) && (!q || c.title.toLowerCase().includes(q) || c.desc.toLowerCase().includes(q)));
    if(sort === 'new'){ /* demo: keep order */ }
    else if(sort === 'price-asc'){ items = items.sort((a,b)=>a.price-b.price); }
   
    resultCount.textContent = `${items.length} course${items.length!==1?'s':''} found`;
   
    coursesGrid.innerHTML = '';
    items.forEach(course => {
      const el = document.createElement('article'); el.className = 'course';
      el.innerHTML = `
        <div class="thumb"><img loading="lazy" src="${escape(course.img)}" alt="${escape(course.title)}"></div>
        <div>
          <div class="title">${escape(course.title)}</div>
          <div class="txt-sm muted">${escape(course.instructor)} • ${escape(course.duration)}</div>
          <div class="meta" style="margin-top:8px">
            <div class="muted">${course.rating} ★</div>
            <div class="enroll">
              <div class="muted">${formatPrice(course.price)}</div>
              <button class="chip" data-action="view" data-id="${course.id}">Details</button>
              <button class="chip" data-action="enroll" data-id="${course.id}">${STATE.enrolled[course.id] ? 'Enrolled' : 'Enroll'}</button>
            </div>
          </div>
        </div>
      `;
      coursesGrid.appendChild(el);
    });

  
    coursesGrid.querySelectorAll('[data-action="view"]').forEach(b => b.addEventListener('click', e => openCourseModal(e.target.dataset.id)));
    coursesGrid.querySelectorAll('[data-action="enroll"]').forEach(b => b.addEventListener('click', e => toggleEnroll(e.target.dataset.id)));
  }

 
  function openCourseModal(courseId){
    const c = CATALOG.find(x => x.id === courseId);
    if(!c) return;
    modal.innerHTML = `
      <div style="display:flex;justify-content:space-between;align-items:center">
        <h2 style="margin:0">${escape(c.title)}</h2>
        <div class="txt-sm muted">${formatPrice(c.price)} • ${c.rating} ★</div>
      </div>
      <div style="margin-top:12px" class="grid-md">
        <div>
          <img src="${escape(c.img)}" alt="${escape(c.title)}" style="width:100%;height:220px;object-fit:cover;border-radius:10px">
          <p class="muted" style="margin-top:12px">${escape(c.desc)}</p>
          <h4 style="margin-top:12px">Syllabus</h4>
          <ol style="margin:8px 0 0 18px" class="txt-sm">
            ${c.lessons.map(ls => `<li>${escape(ls.title)} — <span class="muted">${ls.duration}</span></li>`).join('')}
          </ol>
        </div>
        <aside style="padding-left:8px">
          <div style="display:flex;gap:8px;align-items:center">
            <div style="width:64px;height:64px;border-radius:8px;background:#081827;display:grid;place-items:center">${escape(c.instructor.split(' ')[0][0])}</div>
            <div>
              <div style="font-weight:700">${escape(c.instructor)}</div>
              <div class="txt-sm muted">Instructor</div>
            </div>
          </div>
          <div style="margin-top:12px">
            <button id="modalEnroll" class="button">${STATE.enrolled[c.id] ? 'Go to Course' : 'Enroll now'}</button>
            <div style="margin-top:8px" class="txt-sm muted">Secure payment not implemented — enrollment is demo-only.</div>
          </div>
        </aside>
      </div>
    `;
    modalBack.style.display = 'flex';
    $('#modalEnroll').addEventListener('click', () => {
      if(!STATE.enrolled[c.id]) toggleEnroll(c.id);
      openCoursePlayer(c.id);
      closeModal();
    });
  }

  function closeModal(){ modalBack.style.display = 'none'; modal.innerHTML = ''; }

  modalBack.addEventListener('click', (e) => { if(e.target === modalBack) closeModal(); });

 
  function toggleEnroll(courseId){
    if(STATE.enrolled[courseId]) {
      delete STATE.enrolled[courseId];
      delete STATE.progress[courseId];
    } else {
      STATE.enrolled[courseId] = Date.now();
      STATE.progress[courseId] = 0; // percent
    }
    saveState();
    renderGrid();
    renderMyCourses();
  }

  
  function renderMyCourses(){
    myCoursesWrap.innerHTML = '';
    const entries = Object.keys(STATE.enrolled);
    if(entries.length === 0){
      myCoursesWrap.innerHTML = '<div class="muted txt-sm">You are not enrolled in any course yet.</div>';
      updateOverall();
      return;
    }
    entries.forEach(id => {
      const c = CATALOG.find(x=>x.id===id);
      const pct = STATE.progress[id] || 0;
      const div = document.createElement('div');
      div.className = 'mycourse';
      div.innerHTML = `
        <img src="${escape(c.img)}" alt="${escape(c.title)}">
        <div style="flex:1">
          <div style="font-weight:700">${escape(c.title)}</div>
          <div class="muted txt-sm">${escape(c.instructor)}</div>
          <div style="margin-top:6px" class="progress"><i style="width:${pct}%"></i></div>
        </div>
        <div style="display:flex;flex-direction:column;gap:6px">
          <button class="chip" data-continue="${c.id}">Continue</button>
          <button class="chip" data-unenroll="${c.id}">Unenroll</button>
        </div>
      `;
      myCoursesWrap.appendChild(div);
    });
    myCoursesWrap.querySelectorAll('[data-continue]').forEach(b=>b.addEventListener('click', e => openCoursePlayer(e.target.dataset.continue)));
    myCoursesWrap.querySelectorAll('[data-unenroll]').forEach(b=>b.addEventListener('click', e => {
      if(confirm('Unenroll from this course?')){ toggleEnroll(e.target.dataset.unenroll); }
    }));
    updateOverall();
  }

 
  function updateOverall(){
    const keys = Object.keys(STATE.enrolled);
    if(keys.length === 0){ overallBar.style.width = '6%'; overallPct.textContent = '0%'; return; }
    const avg = Math.round(keys.reduce((s,k)=>s + (STATE.progress[k]||0), 0) / keys.length);
    overallBar.style.width = (Math.max(6, avg)) + '%';
    overallPct.textContent = `${avg}%`;
  }

 
  function openCoursePlayer(courseId){
    const c = CATALOG.find(x=>x.id===courseId); if(!c) return;
    playerArea.style.display = 'block';
    playerArea.scrollIntoView({behavior:'smooth', block:'start'});
    $('#videoArea').textContent = `Playing: ${c.title} — ${c.lessons[0]?.title || ''}`;
  
    lessonsList.innerHTML = '';
    c.lessons.forEach((ls, idx) => {
      const l = document.createElement('div');
      l.className = 'lesson' + (idx===0 ? ' active' : '');
      l.innerHTML = `<div>${escape(ls.title)}</div><div class="muted txt-sm">${ls.duration}</div>`;
      lessonsList.appendChild(l);
      l.addEventListener('click', () => {
       
        lessonsList.querySelectorAll('.lesson').forEach(x=>x.classList.remove('active'));
        l.classList.add('active');
        $('#videoArea').textContent = `Playing: ${c.title} — ${ls.title}`;
        
        const prev = STATE.progress[courseId] || 0;
        STATE.progress[courseId] = Math.min(100, prev + Math.round(100 / c.lessons.length));
        saveState(); renderMyCourses();
      });
    });
  }

  
  function openQuizModal(){
    const qset = [
      {q:'What does "DOM" stand for?', opts:['Document Object Model','Data Object Model','Document Option Model'], a:0},
      {q:'Which CSS property controls layout in 2D?', opts:['display','transform','position'], a:0},
      {q:'React hook for state is?', opts:['useState','setState','stateHook'], a:0}
    ];
    let idx=0, score=0;
    function show(){
      const q = qset[idx];
      modal.innerHTML = `<h3>Quick quiz (${idx+1}/${qset.length})</h3>
        <div class="quiz-q" style="margin-top:8px"><strong>${escape(q.q)}</strong></div>
        <div style="margin-top:8px;display:flex;flex-direction:column;gap:8px">
          ${q.opts.map((o,i)=>`<button class="chip" data-answer="${i}">${escape(o)}</button>`).join('')}
        </div>
        <div style="margin-top:12px"><button class="btn" id="quitQuiz">Quit</button></div>`;
      modalBack.style.display='flex';
      modal.querySelectorAll('[data-answer]').forEach(b => b.addEventListener('click', e => {
        const a = Number(e.currentTarget.dataset.answer);
        if(a === q.a) score++;
        idx++;
        if(idx < qset.length) show(); else finish();
      }));
      $('#quitQuiz').addEventListener('click', ()=> closeModal());
    }
    function finish(){
      modal.innerHTML = `<h3>Quiz finished</h3><p class="muted">You scored ${score} / ${qset.length}</p><div style="margin-top:12px"><button class="btn" id="closeQuiz">Close</button></div>`;
      $('#closeQuiz').addEventListener('click', ()=> closeModal());
    }
    show();
  }

  
  function openProfileModal(){
    modal.innerHTML = `<h3>Your profile</h3>
      <div style="display:flex;gap:12px;align-items:center;margin-top:10px">
        <div class="avatar">S</div>
        <div>
          <div style="font-weight:700">Student</div>
          <div class="txt-sm muted">learnly.user@example.com</div>
        </div>
      </div>
      <div style="margin-top:12px" class="txt-sm muted">This is a demo profile. Data is stored locally.</div>
      <div style="margin-top:12px"><button class="btn" id="closeProfile">Close</button></div>`;
    modalBack.style.display = 'flex';
    $('#closeProfile').addEventListener('click', closeModal);
  }

 
  function escape(s){ return String(s).replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c])); }
  function closeModal(){ modalBack.style.display='none'; modal.innerHTML=''; }
 
  function renderMyCourses(){ /* placeholder filled above */ }

 
  function scrollToDashboard(){ document.querySelector('.sidebar').scrollIntoView({behavior:'smooth'}); }


  function init(){
    renderGrid();
    renderMyCourses();
    updateOverall();
  }
  init();

  return { CATALOG, STATE, renderGrid, openCourseModal };
})();

/* Accessibility: close modal via ESC */
window.addEventListener('keydown', e => {
  if(e.key === 'Escape') document.getElementById('modalBack').style.display = 'none';
});